import{_ as t,o as r,c as e,a2 as l}from"./chunks/framework.BwNZcjNV.js";const b=JSON.parse('{"title":"IBS 워크스페이스(Workspace) 시작하기","description":"","frontmatter":{},"headers":[],"relativePath":"intro/getting-started.md","filePath":"intro/getting-started.md","lastUpdated":1784206612000}'),o={name:"intro/getting-started.md"};function i(s,a,n,h,d,u){return r(),e("div",null,[...a[0]||(a[0]=[l('<h1 id="ibs-워크스페이스-workspace-시작하기" tabindex="-1">IBS 워크스페이스(Workspace) 시작하기 <a class="header-anchor" href="#ibs-워크스페이스-workspace-시작하기" aria-label="Permalink to &quot;IBS 워크스페이스(Workspace) 시작하기&quot;">​</a></h1><blockquote><p><strong>IBS 워크스페이스</strong>는 부동산 개발사업의 전 과정을 &#39;업무(Issue)&#39; 중심으로 관리하고 협업할 수 있는 사용자 친화적인 업무 환경을 제공합니다.</p></blockquote><blockquote><p>이 문서는 신규 사용자가 시스템에 접속하여 팀 워크스페이스를 구성하고 첫 업무를 시작하는 과정을 안내합니다.</p></blockquote><h2 id="이-문서의-대상" tabindex="-1">이 문서의 대상 <a class="header-anchor" href="#이-문서의-대상" aria-label="Permalink to &quot;이 문서의 대상&quot;">​</a></h2><ul><li><strong>사업관리/현장 팀원</strong> - 부지 매입, 인허가 및 공정 관리를 수행하는 실무자</li><li><strong>분양/영업 담당자</strong> - 고객 응대, 계약 및 수납 업무를 수행하는 담당자</li><li><strong>재무/자금 팀원</strong> - 사업 예산 관리 및 수지 분석을 담당하는 전문가</li><li><strong>경영진 및 의사결정자</strong> - 실시간 보고서를 통해 사업 현황을 파악하는 경영진</li></ul><h2 id="ibs-워크스페이스의-업무-흐름" tabindex="-1">IBS 워크스페이스의 업무 흐름 <a class="header-anchor" href="#ibs-워크스페이스의-업무-흐름" aria-label="Permalink to &quot;IBS 워크스페이스의 업무 흐름&quot;">​</a></h2><p>IBS 워크스페이스는 프로젝트의 업무와 핵심 데이터를 하나의 워크스페이스에서 관리하고, 팀원들이 실시간으로 협업할 수 있도록 설계되었습니다.</p><ol><li><strong>프로젝트 생성 (관리자)</strong> - 전사, 부서 또는 현장 단위의 프로젝트를 생성합니다.</li><li><strong>프로젝트 멤버 초대</strong> - 프로젝트에 참여할 구성원을 초대합니다.</li><li><strong>프로젝트 설정</strong> - 프로젝트 기본 정보와 마스터 데이터를 설정합니다.</li><li><strong>업무 및 데이터 관리</strong> - 업무(Issue)와 계약, 토지, 고객, 수납 등 실무 데이터를 함께 관리합니다.</li><li><strong>협업 및 진행 현황 공유</strong> - 업무 진행 상황과 변경 이력을 팀원들과 공유하고 실시간으로 협업합니다.</li></ol><h2 id="시스템-접속-및-가입" tabindex="-1">시스템 접속 및 가입 <a class="header-anchor" href="#시스템-접속-및-가입" aria-label="Permalink to &quot;시스템 접속 및 가입&quot;">​</a></h2><h3 id="접속-주소" tabindex="-1">접속 주소 <a class="header-anchor" href="#접속-주소" aria-label="Permalink to &quot;접속 주소&quot;">​</a></h3><blockquote><p><strong><a href="https://ibs.dyibs.com" target="_blank" rel="noreferrer">https://ibs.dyibs.com</a></strong></p></blockquote><h3 id="계정-생성-및-시작하기" tabindex="-1">계정 생성 및 시작하기 <a class="header-anchor" href="#계정-생성-및-시작하기" aria-label="Permalink to &quot;계정 생성 및 시작하기&quot;">​</a></h3><h4 id="_1-회원-가입-직원용" tabindex="-1">1. 회원 가입 (직원용) <a class="header-anchor" href="#_1-회원-가입-직원용" aria-label="Permalink to &quot;1. 회원 가입 (직원용)&quot;">​</a></h4><ul><li>메인 화면의 가입 링크를 통해 본인의 아이디를 생성합니다.</li><li>가입 시 사내 보안 코드인 **계정 생성코드(<code>dyibs-staff</code>)**를 반드시 입력해야 합니다.</li></ul><h4 id="_2-권한-승인-및-프로젝트-참여" tabindex="-1">2. 권한 승인 및 프로젝트 참여 <a class="header-anchor" href="#_2-권한-승인-및-프로젝트-참여" aria-label="Permalink to &quot;2. 권한 승인 및 프로젝트 참여&quot;">​</a></h4><ul><li>가입 완료 후 시스템 관리자에게 접속하려는 프로젝트(워크스페이스)의 참여 승인을 요청합니다.</li><li>승인이 완료되면 사이드바에서 해당 프로젝트의 모든 메뉴가 활성화됩니다.</li></ul><h2 id="초기-데이터-설정-5단계" tabindex="-1">초기 데이터 설정 5단계 <a class="header-anchor" href="#초기-데이터-설정-5단계" aria-label="Permalink to &quot;초기 데이터 설정 5단계&quot;">​</a></h2><p>워크스페이스를 처음 시작할 때는 다음 순서로 데이터를 구축하는 것이 효율적입니다.</p><h3 id="_1단계-프로젝트-기본-정보" tabindex="-1">1단계: 프로젝트 기본 정보 <a class="header-anchor" href="#_1단계-프로젝트-기본-정보" aria-label="Permalink to &quot;1단계: 프로젝트 기본 정보&quot;">​</a></h3><ul><li>사업명, 위치, 기간 등 프로젝트의 기본 정보를 설정합니다.</li></ul><h3 id="_2단계-상품-정보-구성" tabindex="-1">2단계: 상품 정보 구성 <a class="header-anchor" href="#_2단계-상품-정보-구성" aria-label="Permalink to &quot;2단계: 상품 정보 구성&quot;">​</a></h3><ul><li>분양 대상 동·호수와 유닛 타입 등 상품 정보를 등록합니다.</li></ul><h3 id="_3단계-계약-및-수지-조건-설정" tabindex="-1">3단계: 계약 및 수지 조건 설정 <a class="header-anchor" href="#_3단계-계약-및-수지-조건-설정" aria-label="Permalink to &quot;3단계: 계약 및 수지 조건 설정&quot;">​</a></h3><ul><li>분양 가격과 계약 회차, 납부 조건을 설정합니다.</li><li>예산 항목을 구성하여 사업 수지와 자금 집행의 기준을 마련합니다.</li></ul><h3 id="_4단계-기존-데이터-등록" tabindex="-1">4단계: 기존 데이터 등록 <a class="header-anchor" href="#_4단계-기존-데이터-등록" aria-label="Permalink to &quot;4단계: 기존 데이터 등록&quot;">​</a></h3><ul><li>기존 프로젝트의 토지, 계약, 고객 등 운영 데이터를 시스템으로 등록하거나 일괄 이관합니다.</li></ul><h3 id="_5단계-첫-업무-issue-발행" tabindex="-1">5단계: 첫 업무(Issue) 발행 <a class="header-anchor" href="#_5단계-첫-업무-issue-발행" aria-label="Permalink to &quot;5단계: 첫 업무(Issue) 발행&quot;">​</a></h3><ul><li>현재 진행 중인 핵심 업무를 등록하고 담당자를 지정한 후, 관련 팀원을 지켜보기(Watcher)에 추가하여 업무를 공유합니다.</li></ul><h2 id="사용자-친화적-기능-활용-팁" tabindex="-1">사용자 친화적 기능 활용 팁 <a class="header-anchor" href="#사용자-친화적-기능-활용-팁" aria-label="Permalink to &quot;사용자 친화적 기능 활용 팁&quot;">​</a></h2><ul><li><strong>프로젝트 전환</strong> - 상단 메뉴를 통해 여러 프로젝트를 원클릭으로 이동할 수 있습니다.</li><li><strong>이슈 알림</strong> - 나에게 할당된 업무나 관심 있는 업무의 변경 사항을 실시간으로 확인합니다.</li><li><strong>다크/라이트 테마</strong> - 사용자 취향에 맞는 테마를 선택하여 눈의 피로도를 조절합니다.</li><li><strong>최근 방문 메뉴</strong> - 최근에 방문했던 메뉴들이 상단에 유지되어 재방문이 편리합니다.</li></ul><h2 id="도움-요청-및-기술-지원" tabindex="-1">도움 요청 및 기술 지원 <a class="header-anchor" href="#도움-요청-및-기술-지원" aria-label="Permalink to &quot;도움 요청 및 기술 지원&quot;">​</a></h2><p>시스템 사용 중 궁금한 점이 생기면 언제든지 문의해 주세요.</p><ul><li><strong>사내 커뮤니티</strong>: <a href="https://ibs.dyibs.com/#/work/project/ibs/boards/1" target="_blank" rel="noreferrer">IBS 기술지원 게시판</a></li><li><strong>관리 부서</strong>: IT·디지털혁신팀</li><li><strong>문의 방법</strong>: 오류 현상의 화면 캡처와 함께 메뉴명을 기재하여 게시판에 등록</li></ul><hr><p><strong>IBS 워크스페이스</strong>가 여러분의 업무를 더욱 효율적이고 체계적으로 관리하는 데 도움이 되기를 바랍니다.</p>',35)])])}const g=t(o,[["render",i]]);export{b as __pageData,g as default};
